),(171,565),(190,565),(106,590),(106,597),(107,615),(109,630),(162,630),(167,630),(110,649),(143,649),(141,757),(164,757),(194,757),(141,762),(173,762),(142,780),(160,780),(187,780),(143,788),(164,788),(174,788),(188,788),(144,799),(153,799),(166,799),(144,803),(146,819),(154,914),(161,914),(160,982),(162,1004),(164,1028),(174,1028),(165,1041),(168,1041),(174,1041),(188,1041),(175,1152),(179,1198),(179,1200),(188,1297),(190,1321),(190,1324),(192,1346),(194,1389);
